def construct_query(search_criteria):
    where_clause = []
    for criterion in search_criteria:
        field = criterion['field']
        op = criterion['op']
        value = criterion['value']
        if op == '=':
            where_clause.append(f"{field} = '{value}'")
        elif op == '>':
            where_clause.append(f"{field} > {value}")
        elif op == '<':
            where_clause.append(f"{field} < {value}")
        elif op == 'LIKE':
            where_clause.append(f"{field} LIKE '%{value}%'")
    return f"SELECT * FROM your_table WHERE {' AND '.join(where_clause)}"

